<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('student');$student=db_one('SELECT s.id,s.student_number,u.name,u.email,c.name class_name FROM students s JOIN users u ON u.id=s.user_id LEFT JOIN classes c ON c.id=s.class_id WHERE s.user_id=:id',['id'=>current_user()['id']]);$statuses=db_one('SELECT COALESCE(fc.status,"pending") finance,COALESCE(rc.status,"pending") registration,COALESCE(ec.status,"pending") exam,COALESCE(fic.status,"pending") final FROM students s LEFT JOIN finance_clearance fc ON fc.student_id=s.id LEFT JOIN registration_clearance rc ON rc.student_id=s.id LEFT JOIN exam_clearance ec ON ec.student_id=s.id LEFT JOIN final_clearance fic ON fic.student_id=s.id WHERE s.id=:id',['id'=>$student['id']]);if(query('download')==='1'){header('Content-Type: text/html; charset=UTF-8');header('Content-Disposition: attachment; filename="clearance-'.$student['student_number'].'.html"');}$approved=fn(string $v):string=>in_array($v,['approved','cleared'],true)?'Approved':'Pending';?>
<!doctype html><html><head><meta charset="utf-8"><title>Consolidated Clearance</title><style>body{font:15px Arial;color:#17203b;padding:40px;max-width:800px;margin:auto}header{border-bottom:4px solid #f26b4f;padding-bottom:20px;margin-bottom:30px}h1{font-family:Georgia;font-size:34px}.meta{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:25px 0}.item{display:flex;justify-content:space-between;padding:18px;border-bottom:1px solid #ddd}.approved{color:#167557;font-weight:bold}.pending{color:#b47514;font-weight:bold}.actions{margin:25px 0}@media print{.actions{display:none}}</style></head><body><header><strong>SMIS / Freetown Technical University</strong><h1>Consolidated Clearance Document</h1><p>Generated <?=date('F j, Y')?></p></header><div class="meta"><div><b>Student</b><br><?=e($student['name'])?></div><div><b>Student Number</b><br><?=e($student['student_number'])?></div><div><b>Class</b><br><?=e($student['class_name']??'-')?></div><div><b>Email</b><br><?=e($student['email'])?></div></div><?php foreach(['registration'=>'Registration Clearance','finance'=>'Financial Clearance','exam'=>'Examination Clearance','final'=>'Final Clearance Status'] as $key=>$label):$value=$approved($statuses[$key]);?><div class="item"><strong><?=$label?></strong><span class="<?=strtolower($value)?>"><?=$value?></span></div><?php endforeach?><div class="actions"><a href="?download=1">Download document</a> · <button onclick="window.print()">Print / Save as PDF</button> · <a href="<?=url('student/dashboard.php')?>">Back</a></div></body></html>
